#include <stdio.h>
#include <sys/mman.h>
#include <fcntl.h>
#include <unistd.h>
#include <string.h>
int main(void) {
    const char *path = "/tmp/kf_mmap.txt";
    int fd = open(path, O_CREAT | O_RDWR | O_TRUNC, 0644);
    const char *data = "Hello mmap world!";
    write(fd, data, strlen(data));
    size_t len = strlen(data);
    char *mapped = (char *)mmap(NULL, len,
        PROT_READ | PROT_WRITE,
        MAP_SHARED, fd, 0);
    if (mapped == MAP_FAILED) { perror("mmap"); close(fd); return 1; }
    close(fd);
    printf("Mapped: %s\n", mapped);
    mapped[0] = 'J';
    printf("Modified: %s\n", mapped);
    munmap(mapped, len);
    fd = open(path, O_RDONLY);
    char buf[64];
    ssize_t n = read(fd, buf, sizeof(buf) - 1);
    buf[n] = '\0';
    printf("File after: %s\n", buf);
    close(fd);
    unlink(path);
    return 0;
}

