void example_private(void) {
    const char *p = "/tmp/kf_ex_priv.txt";
    int fd = open(p, O_CREAT|O_RDWR|O_TRUNC, 0644);
    write(fd, "private", 7);
    char *m = mmap(NULL, 7, PROT_READ|PROT_WRITE, MAP_PRIVATE, fd, 0);
    close(fd);
    m[0] = 'P';
    printf("Private mod: %.7s\n", m); /* Pne voit pas dans fichier */
    munmap(m, 7); unlink(p);
}

